21	const PROCESSING_FEE_G = 5;
22	const FIRST_INSURANCE_SURCHARGE_DIVISOR = 10; // 10% surcharge = divide by 10
23	const TENTHS_PER_G = 10;
24	
25	const quotePremium = (items: Item[]): number => {
26	  const itemBaseTenths = items.reduce(
27	    (sum, item) => sum + BASE_PREMIUMS[item.type] * TENTHS_PER_G,
28	    0,
29	  );
30	  const withFirstInsuranceTenths =
31	    itemBaseTenths + itemBaseTenths / FIRST_INSURANCE_SURCHARGE_DIVISOR;
32	  const totalTenths = withFirstInsuranceTenths + PROCESSING_FEE_G * TENTHS_PER_G;
33	  return Math.ceil(totalTenths / TENTHS_PER_G);
34	};
35	
36	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
37	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
38	  return { results };
39	};
